const entryDate = $input.first().json.currentDate; // Expects ISO 8601 string with timezone

// Parse ISO string into Date object
const dateObj = new Date(entryDate);

// Options for 'MMMM D, YYYY at h:mm a'
const options1 = {
  timeZone: 'America/Toronto',
  year: 'numeric',
  month: 'long',
  day: 'numeric',
  hour: 'numeric',
  minute: '2-digit',
  hour12: true,
};
const entry_datetime = dateObj.toLocaleString('en-CA', options1).replace(',', ' at');

// Options for 'YYYY-MM-DD | HH:mm'
const options2 = {
  timeZone: 'America/Toronto',
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
  hour: '2-digit',
  minute: '2-digit',
  hour12: false,
};
const localeStr2 = dateObj.toLocaleString('en-CA', options2).replace(',', '');
const [dateCA, timeCA] = localeStr2.split(' ');
const log_datetime = `${dateCA} | ${timeCA}`;

return [
  {
    json: {
      entry_datetime,
      log_datetime,
    }
  }
];

// Example inputs
const log_datetime = $input.first().json['Log Date and Time'];
const current_datetime = $input.first().json['Current Date and Time'];

// Function to parse "YYYY-MM-DD | HH:mm TZ"
function parseDate(dateString) {
  // Replace " | " with " " and let Date parse it with timezone
  const cleaned = dateString.replace(" | ", " ");
  return new Date(cleaned);
}

const logDate = parseDate(log_datetime);
const currentDate = parseDate(current_datetime);

// Calculate difference in milliseconds
const diffMs = currentDate - logDate;

// Convert ms → hours
const diffHours = diffMs / (1000 * 60 * 60);

// Check if 3 days (72 hours) have passed
const has3DaysPassed = diffHours >= 72;

// Return result
return [{ json: { has3DaysPassed } }];

